"use strict";function DetectScroll(){$(window).on("scroll",function(){$(window).scrollTop()>=330?$("header").addClass("sticky"):$("header").removeClass("sticky")})}function SmoothScroll(n){n.length&&$("html, body").animate({scrollTop:$($.attr(this,n)).offset().top},500)}function HideIcon(){$(".MenuIcon").css("display","none")}function ShowIcon(){$(".MenuIcon").css("display","flex")}function LoadMore(){$(function(){$(".mud-paper").hide();$(".mud-paper").slice(0,3).show();x=3;$(".loadMorePosts").on("click",function(n){n.preventDefault();x=x+1;$(".mud-paper").slice(0,x).show()})})}function HideContent(){$("#MainContent").hide()}function LoadCKEditor(){}